def main():
    n = int(input())
    points = []
    for i in range(n):
        x, y = map(int, input().split())
        points.append((x, y))
    lines = []
    for i in range(n):
        for j in range(i+1, n):
            x1, y1 = points[i]
            x2, y2 = points[j]
            if x1 == x2:
                lines.append((x1, 0))
            else:
                slope = (y2 - y1) / (x2 - x1)
                intercept = y1 - slope * x1
                lines.append((slope, intercept))
    count = {}
    for line in lines:
        count[line] = count.get(line, 0) + 1
    good_lines = sum(1 for line, c in count.items() if c >= 2)
    if good_lines == len(lines):
        print(-1)
    else:
        print(good_lines)

if __name__ == '__main__':
    main()
